(62773, 'esMX', 'Completa todos los siguientes logros de pescadores abisales.', 'Pescadores abisales: Flamante rival de Jeju', '', 67186),
(61883, 'esMX', 'Evita que te marquen durante el primer minuto de Duelo de decoraciones (x3).', 'Ahora no me ven...', '', 67186),
(61887, 'esMX', 'Completa todos los logros de Duelo de decoraciones.', 'Disfraz impecable', '', 67186),
(61886, 'esMX', 'Consigue acceder a todas las mejoras de kit en Duelo de decoraciones.', 'Colección completa', '', 67186),
(61882, 'esMX', 'Pierde el estado de encontrado sin que te marquen en Duelo de decoraciones.', 'Nulidad y evasión', '', 67186),
(61881, 'esMX', 'Sé $gel último escondido:la última escondida; de tu equipo sin marcar en Duelo de decoraciones.', 'Escondido y escurridizo', '', 67186),
(61880, 'esMX', 'Escóndete y evita que te encuentren durante un minuto y medio de corrido en Duelo de decoraciones.', 'Son frías las sombras', '', 67186),
(61879, 'esMX', 'Gana una ronda como buscador marcando a todos los escondidos en menos de dos minutos en Duelo de decoraciones.', 'Tú la traes', '', 67186),
(61878, 'esMX', 'Marca a otros jugadores como forestales arcanos en Duelo de decoraciones.', 'Marcado y capturado', '', 67186),
