(12009, 'esMX', 'Derrota a L\'ura en Trono del Triunvirato mientras todos los miembros del grupo están afectados por Oscuridad aplastante en dificultad mítica.', 'El lado más oscuro', '', 67186),
(12005, 'esMX', 'Haz que Colmillo umbrío destruya 4 alijos del Vacío sellados con Salto de las sombras y luego derrota a Saprish en Trono del Triunvirato en dificultad mítica.', 'Frenesí saltarín', '', 67186),
(12004, 'esMX', 'Haz que aparezca Urjad desde el reino del Vacío con Grieta del Vacío y derrótalo a él y a Zuraal, el Ascendido en el Trono del Triunvirato en dificultad mítica.', 'Bienvenido al Vacío', '', 67186),
(9036, 'esMX', 'Derrota a la Gran Sabia Viryx en Trecho Celestial en dificultad heroica sin matar a ningún constructor de escudos.', 'Monomanía', '', 67186),
(9035, 'esMX', 'Haz que tres pilas de ceniza formen Centellas solares al mismo tiempo durante el encuentro con Rukhran en Trecho Celestial en dificultad heroica.', 'Vi a Solis', '', 67186),
(9034, 'esMX', 'Derrota al Ensamblaje potenciado en Trecho Celestial en dificultad heroica.', 'Magnificar... mejora', '', 67186),
(9033, 'esMX', 'Derrota a Ranjit en Trecho Celestial, en dificultad heroica, sin que te dañen las siguientes habilidades: Filo giratorio, Muro de viento, Cuatro Vientos, Destello luminoso.', 'Listo para asaltar IV', '', 67186),
(4525, 'esMX', 'Limpia la cámara antes del Señor de la Plaga Tyrannus en El Foso de Saron en dificultad heroica sin que nadie reciba daño de carámbanos en el primer intento.', 'No mires hacia arriba', '', 67186),
(4524, 'esMX', 'Derrota al maestro de forja Gargelus en el Foso de Saron en dificultad heroica antes de que un jugador acumule 11 veces el efecto Escarcha permanente.', 'Solo once campanadas', '', 67186),
