INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'esMX', 'Núcleo del Vacío nebuloso', 'Se puede transmutar en equipo poderoso al derrotar a enemigos fuertes en bandas de la temporada 1 de Midnight o al completar calabozos míticos+, abismos abundantes y cacerías de presa en dificultad pesadilla.', 67186),
(3347, 'esMX', 'Crestalborada mítica', 'Se utiliza para mejorar el equipo mítico durante la temporada 1 de Midnight hasta los niveles de objeto 276-289.  \n\nCuando se usa para la fabricación, establece el nivel de objeto resultante en 272-285 según la calidad.\n\nSe obtiene de las siguientes actividades:\n\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (mítico)\n- Calabozos de piedra angular mítica (nivel 9 y superior)', 67186),
(3346, 'esMX', 'Crestalborada de héroe', 'Se utiliza para mejorar el equipo de héroe durante la temporada 1 de Midnight hasta los niveles de objeto 263-276. Se obtiene de las siguientes actividades:\n\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (heroico)\n- Calabozos de piedra angular mítica (+4 a +8)\n- Abismos (nivel 11)\n- Botín de buscador de tesoros (nivel 8 y superior)\n- Cacerías de Presa (pesadilla)', 67186),
(3345, 'esMX', 'Crestalborada de héroe', 'Se utiliza para mejorar el equipo de héroe durante la temporada 1 de Midnight hasta los niveles de objeto 263-276.  \n\nCuando se usa para la fabricación, establece el nivel de objeto resultante en 259-272 según la calidad.\n\nSe obtiene de las siguientes actividades:\n\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (heroico)\n- Calabozos de piedra angular mítica (+4 a +8)\n- Abismos (nivel 11)\n- Botín de buscador de tesoros (nivel 8 y superior)\n- Cacerías de Presa (pesadilla)', 67186),
(3344, 'esMX', 'Crestalborada de campeón', 'Se utiliza para mejorar el equipo de campeón durante la temporada 1 de Midnight hasta los niveles de objeto 250-263. Se obtiene de las siguientes actividades:\n\n- Eventos de exterior semanales\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (normal)\n- Calabozos míticos de temporada\n- Calabozos de piedra angular mítica (+2 a +3)\n- Abismos (niveles 7 a 10)\n- Botín de buscador de tesoros (niveles 6 a 7)\n- Cacerías de Presa (pesadilla)', 67186),
(3343, 'esMX', 'Crestalborada de campeón', 'Se utiliza para mejorar el equipo de campeón durante la temporada 1 de Midnight hasta los niveles de objeto 250-263. Se obtiene de las siguientes actividades:\n\n- Eventos de exterior semanales\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (normal)\n- Calabozos míticos de temporada\n- Calabozos de piedra angular mítica (+2 a +3)\n- Abismos (niveles 7 a 10)\n- Botín de buscador de tesoros (niveles 6 a 7)\n- Cacerías de Presa (pesadilla)', 67186),
(3342, 'esMX', 'Crestalborada de veterano', 'Se utiliza para mejorar el equipo de veterano durante la temporada 1 de Midnight hasta los niveles de objeto 237-250. Se obtiene de las siguientes actividades:\n\n- Eventos de exterior repetibles\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (buscador de bandas)\n- Calabozos heroicos de temporada\n- Abismos (niveles 5 a 6)\n- Botín de buscador de tesoros (niveles 4 a 5)\n- Cacerías de Presa (difícil)', 67186),
(3341, 'esMX', 'Crestalborada de veterano', 'Se utiliza para mejorar el equipo de veterano durante la temporada 1 de Midnight hasta los niveles de objeto 237-250. \n\nCuando se usa para la fabricación, establece el nivel de objeto resultante en 233-246 según la calidad.\n\nSe obtiene de las siguientes actividades:\n\n- Eventos de exterior repetibles\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (buscador de bandas)\n- Calabozos heroicos de temporada\n- Abismos (niveles 5 a 6)\n- Botín de buscador de tesoros (niveles 4 a 5)\n- Cacerías de Presa (difícil)', 67186),
(3418, 'esMX', 'Núcleo del Vacío nebuloso', 'Se puede transmutar en equipo poderoso al derrotar a enemigos fuertes en bandas de la temporada 1 de Midnight o al completar calabozos míticos+, abismos abundantes y cacerías de presa en dificultad pesadilla.', 67186),
(3391, 'esMX', 'Crestalborada de aventurero', 'Se utiliza para mejorar el equipo de aventurero durante la temporada 1 de Midnight hasta los niveles de objeto 224-237. Se obtiene de las siguientes actividades:\n\n- Eventos de exterior repetibles\n- Abismos de nivel 4\n- Cacerías de Presa (normal)', 67186),
(3383, 'esMX', 'Crestalborada de aventurero', 'Se utiliza para mejorar el equipo de aventurero durante la temporada 1 de Midnight hasta los niveles de objeto 224-237. \n\nCuando se usa para la fabricación, establece el nivel de objeto resultante en 220-233 según la calidad.\n\nSe obtiene de las siguientes actividades:\n\n- Eventos de exterior repetibles\n- Abismos de nivel 4\n- Cacerías de Presa (normal)', 67186),
(3348, 'esMX', 'Crestalborada mítica', 'Se utiliza para mejorar el equipo mítico durante la temporada 1 de Midnight hasta los niveles de objeto 276-289. Se obtiene de las siguientes actividades:\n\n- Aguja del Vacío, La Onirifalla, Marcha sobre Quel\'Danas (heroico)\n- Calabozos de piedra angular mítica (nivel 9 y superior)', 67186);
