INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'esMX', '¡Saludos, $gacólito:acólita;!\n\n¡Contempla la maravilla de este terreno que rebosa de ABUNDANCIA GLORIOSA! ¡Mana, brota, rechaza todo intento de contención!\n\nTu devoción hacia mi divino ser merece una pequeña benevolencia. ¡Esta vez, en la forma de abundancia pura!\n\nY toma nota, gentil $gacólito:acólita;: algunas ofrendas, como la vitalidad fusionada, ahora estarán disponibles con otros comerciantes. Tal vez los encuentres, si es que tus excursiones te llevan cerca de las Profundidades de Zul\'Aman.\n\nTe desea la más maravillosa de las cosechas,\n\n-Dundun, loa de la abundancia', 67186);
